func (s *Store) ListUsers() ([]json.RawMessage, error) {
	return s.queryJSON(`SELECT data FROM users ORDER BY active DESC, display_name, name, email`)
}

func (s *Store) ListIssueLabels(limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 200
	}
	return s.queryJSON(`SELECT data FROM issue_labels ORDER BY COALESCE(team_key, ''), name LIMIT ?`, limit)
}

func (s *Store) GetByID(table string, id string) (json.RawMessage, error) {
	if !allowedEntityTable(table) {
		return nil, fmt.Errorf("unknown table %q", table)
	}
	var data string
	err := s.db.QueryRow(fmt.Sprintf(`SELECT data FROM %s WHERE id = ?`, table), id).Scan(&data)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	return json.RawMessage(data), nil
}

func (s *Store) SaveSyncState(resourceType, cursor string, count int) error {
	return s.UpdateSyncCursor(resourceType, cursor, count)
}

func (s *Store) GetSyncState(resourceType string) (cursor string, lastSynced time.Time, count int, err error) {
	err = s.db.QueryRow(
		`SELECT last_cursor, last_synced_at, total_count FROM sync_state WHERE resource_type = ?`,
		resourceType,
	).Scan(&cursor, &lastSynced, &count)
	if err == sql.ErrNoRows {
		return "", time.Time{}, 0, nil
	}
	return
}

func (s *Store) SaveSyncCursor(resourceType, cursor string) error {
	return s.UpdateSyncCursor(resourceType, cursor, 0)
}

func (s *Store) UpdateSyncCursor(resourceType string, cursor string, count int) error {
	_, err := s.db.Exec(
		`INSERT INTO sync_state (resource_type, last_cursor, last_synced_at, total_count)
		 VALUES (?, ?, CURRENT_TIMESTAMP, ?)
		 ON CONFLICT(resource_type) DO UPDATE SET
		 last_cursor = excluded.last_cursor,
		 last_synced_at = excluded.last_synced_at,
		 total_count = excluded.total_count`,
		resourceType, cursor, count,
	)
	return err
}

func (s *Store) GetSyncCursor(resourceType string) (string, error) {
	var cursor sql.NullString
	err := s.db.QueryRow(`SELECT last_cursor FROM sync_state WHERE resource_type = ?`, resourceType).Scan(&cursor)
	if err == sql.ErrNoRows {
		return "", nil
	}
	if err != nil {
		return "", err
	}
	if cursor.Valid {
		return cursor.String, nil
	}
	return "", nil
}

func (s *Store) GetLastSyncedAt(resourceType string) string {
	var ts sql.NullString
	s.db.QueryRow("SELECT last_synced_at FROM sync_state WHERE resource_type = ?", resourceType).Scan(&ts)
	if ts.Valid {
		return ts.String
	}
	return ""
}

func (s *Store) ClearSyncCursors() error { _, err := s.db.Exec("DELETE FROM sync_state"); return err }

func (s *Store) Query(query string, args ...any) (*sql.Rows, error) {
	return s.db.Query(query, args...)
}

func (s *Store) SQL(query string) ([]map[string]interface{}, error) {
	if !isReadOnlySQL(query) {
		return nil, fmt.Errorf("only read-only SQL is allowed")
	}
	rows, err := s.db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	cols, err := rows.Columns()
	if err != nil {
		return nil, err
	}
	var out []map[string]interface{}
	for rows.Next() {
		vals := make([]interface{}, len(cols))
		ptrs := make([]interface{}, len(cols))
		for i := range vals {
			ptrs[i] = &vals[i]
		}
		if err := rows.Scan(ptrs...); err != nil {
			return nil, err
		}
		row := map[string]interface{}{}
		for i, col := range cols {
			switch v := vals[i].(type) {
			case []byte:
				row[col] = string(v)
			default:
				row[col] = v
			}
		}
		out = append(out, row)
	}
	return out, rows.Err()
}

func (s *Store) Count(resourceType string) (int, error) {
	if !allowedEntityTable(resourceType) {
		return 0, fmt.Errorf("unknown resource type %q", resourceType)
	}
	var count int
	err := s.db.QueryRow(fmt.Sprintf(`SELECT COUNT(*) FROM %s`, resourceType)).Scan(&count)
	return count, err
}

// GroupResult holds one row from a GROUP BY aggregation.
type GroupResult struct {
	Value string `json:"value"`
	Count int    `json:"count"`
}

// GroupBy runs a GROUP BY query on a column in an entity table.
func (s *Store) GroupBy(table, column string, limit int) ([]GroupResult, error) {
	if !allowedEntityTable(table) {
		return nil, fmt.Errorf("unknown resource type %q", table)
	}
	if limit <= 0 {
		limit = 25
	}
	// Validate column exists via PRAGMA
	cols, err := s.tableColumns(table)
	if err != nil {
		return nil, err
	}
	found := false
	for _, c := range cols {
		if c == column {
			found = true
			break
		}
	}
	if !found {
		return nil, fmt.Errorf("column %q not found in %s (available: %s)", column, table, strings.Join(cols, ", "))
	}
	query := fmt.Sprintf(`SELECT COALESCE(%s, '') AS val, COUNT(*) AS cnt FROM %s GROUP BY val ORDER BY cnt DESC LIMIT ?`, column, table)
	rows, err := s.db.Query(query, limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var results []GroupResult
	for rows.Next() {
		var r GroupResult
		if err := rows.Scan(&r.Value, &r.Count); err != nil {
			return nil, err
		}
		results = append(results, r)
	}
	if results == nil {
		results = []GroupResult{}
	}
	return results, rows.Err()
}

func (s *Store) tableColumns(table string) ([]string, error) {
	rows, err := s.db.Query(fmt.Sprintf(`PRAGMA table_info(%s)`, table))
	if err != nil {
		return nil, fmt.Errorf("inspecting %s schema: %w", table, err)
	}
	defer rows.Close()
	var cols []string
	for rows.Next() {
		var cid int
		var name, ctype string
		var notnull, pk int
		var dflt sql.NullString
		if err := rows.Scan(&cid, &name, &ctype, &notnull, &dflt, &pk); err != nil {
			return nil, err
		}
		if name != "data" && name != "synced_at" {
			cols = append(cols, name)
		}
	}
	return cols, rows.Err()
}

func (s *Store) Status() (map[string]int, error) {
	status := make(map[string]int)
	for table := range entityTables {
		var count int
		err := s.db.QueryRow(fmt.Sprintf(`SELECT COUNT(*) FROM %s`, table)).Scan(&count)
		if err != nil {
			continue
		}
		if count > 0 {
			status[table] = count
		}
	}
	return status, nil
}

func (s *Store) ResolveByName(resourceType string, input string, matchFields ...string) (string, error) {
	if IsUUID(input) {
		return input, nil
	}
	var matches []string
	for _, field := range matchFields {
		query := fmt.Sprintf(`SELECT id FROM resources WHERE resource_type = ? AND LOWER(json_extract(data, '$.%s')) = LOWER(?)`, field)
		rows, err := s.db.Query(query, resourceType, input)
		if err != nil {
			continue
		}
		for rows.Next() {
			var id string
			if rows.Scan(&id) == nil && !contains(matches, id) {
				matches = append(matches, id)
			}
		}
		rows.Close()
	}
	switch len(matches) {
	case 0:
		return "", fmt.Errorf("%s %q not found in local store. Run 'sync' first, or use the UUID directly", resourceType, input)
	case 1:
		return matches[0], nil
	default:
		hint := strings.Join(matches, ", ")
		if len(matches) > 5 {
			hint = strings.Join(matches[:5], ", ") + "..."
		}
		return "", fmt.Errorf("ambiguous: %q matches %d %s entries (%s). Use the exact UUID instead", input, len(matches), resourceType, hint)
	}
}

func (s *Store) queryJSON(query string, args ...any) ([]json.RawMessage, error) {
	rows, err := s.db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

func buildFilters(filter map[string]string, allowed map[string]string) (string, []any) {
	if len(filter) == 0 {
		return "", nil
	}
	var clauses []string
	var args []any
	for key, col := range allowed {
		if v := strings.TrimSpace(filter[key]); v != "" {
			clauses = append(clauses, col+" = ?")
			args = append(args, v)
		}
	}
	return strings.Join(clauses, " AND "), args
}

